def error_json(
    self,
    message: str,
    phase: Optional[int] = None,
    task_id: Optional[str] = None,
    fatal: bool = False,
):
    """Emits a structured error JSON event."""
    data = {"message": message, "fatal": fatal}
    if phase is not None:
        data["phase"] = phase
    if task_id:
        data["taskId"] = task_id
    self._emit_json("error", data)

